VALUES
  ('aboriginal-64311456-moex-00377', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關怠金之敘述，下列何者正確？ 連續處以怠金時，得不經書面逕以倍率標準表核算金額，由執行人員口頭告知義務人 因怠金係行為或不行為義務之間接強制，若義務人拒不繳納怠金，則須移送法院執行 怠金為公法上之金錢給付義務，義務人得申請與執行機關進行協議，以減少執行成本 執行機關處以怠金後，義務人仍不履行者，執行機關仍可採取收繳或註銷證照之手段', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00378', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何種金錢給付義務未履行時，應直接移送法務部行政執行署就義務人財產強制執行？ 公有停車場或路邊劃設停車格之停車費  行政契約中約定自願接受強制執行之金錢給付 自來水事業處向用水民眾收取之水費  公有公共設施委託私人經營所收取之權利金', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00379', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者屬於行政執行之間接強制方法？ 罰鍰  代履行  註銷證照  斷水斷電', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00380', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者不得依據行政程序法申請閱覽卷宗？ 行政程序之申請人 行政程序申請人之相對人 因行政程序影響其公、私法上權利或法律上利益之人 行政程序中之證人', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00381', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '行政程序中當事人委任之代理人，其人數上限為何？ 1人  2人  3人  4人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00382', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '下列何者非屬行政處分？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00383', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關行政計畫之敘述，下列何者錯誤？ 行政機關雖享有所謂計畫高權，行政法院非不得審查行政機關所訂定之行政計畫 在大規模之計畫有所謂先行裁決，此種多階段之決定有行政自我拘束原則之適用 如經確定計畫裁決程序，因具核准及形成與集中事權效果，當事人不得再行爭訟 行政機關變更計畫時，人民如有權利受損之情形，仍得依國家賠償法尋求救濟', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00384', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '有關訴願之敘述，下列何者正確？ 原處分機關認為訴願有理由者，應自行撤銷原處分，毋須通知訴願管轄機關 原處分機關認為訴願有理由者，自行撤銷原處分後，訴願管轄機關應為訴願駁回之決定 訴願人誤向訴願管轄機關以外之機關提起訴願者，該機關應為訴願不受理之決定 受理訴願機關認為有必要時，得依職權通知訴願人及原處分機關進行言詞辯論', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00385', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '依訴願法第77條規定，下列何者非屬不受理決定之事由？ 提起訴願逾法定期間    行政處分已不存在 對已撤回之訴願事件重行提起訴願  為決定基礎之證物，係偽造或變造', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00386', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '依訴願法規定，關於訴願審議程序之敘述，下列何者錯誤？ 場陳述意見 日未完備者，得再為辯論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
